import{_ as o,o as e,c as n,ag as r}from"./chunks/framework.DGzMGr_a.js";const p=JSON.parse('{"title":"微前端方案与隔离机制","description":"","frontmatter":{"title":"微前端方案与隔离机制","difficulty":"hard","tags":["微前端","qiankun","single-spa","Module-Federation"],"estimate":25},"headers":[],"relativePath":"domains/arch/qa/qa-09-micro-frontend.md","filePath":"domains/arch/qa/qa-09-micro-frontend.md","lastUpdated":1783504823000}'),i={name:"domains/arch/qa/qa-09-micro-frontend.md"};function a(d,t,s,l,c,u){return e(),n("div",null,[...t[0]||(t[0]=[r('<h1 id="问答-09-高级-微前端方案与隔离机制" tabindex="-1">问答 09（高级）：微前端方案与隔离机制 <a class="header-anchor" href="#问答-09-高级-微前端方案与隔离机制" aria-label="Permalink to &quot;问答 09（高级）：微前端方案与隔离机制&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>请对比常见的微前端方案（qiankun / single-spa / Module Federation）的原理，并说明微前端在 JS 沙箱、样式隔离方面的常见做法与坑。</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>微前端要解决什么</strong></p><ul><li>把大型前端应用拆成多个可独立开发、独立部署、独立技术栈的<strong>子应用</strong>，在一个主应用（壳）里聚合。</li><li>关键需求：路由分发、子应用生命周期管理、JS / CSS 隔离、跨应用通信、公共依赖共享。</li></ul><p><strong>方案对比</strong></p><table tabindex="0"><thead><tr><th>方案</th><th>定位</th><th>原理要点</th></tr></thead><tbody><tr><td><strong>single-spa</strong></td><td>微前端&quot;内核&quot;框架</td><td>提供子应用注册与生命周期钩子（bootstrap/mount/unmount），路由匹配后加载对应子应用</td></tr><tr><td><strong>qiankun</strong></td><td>基于 single-spa 的开箱即用方案</td><td>补足了资源加载、JS 沙箱、样式隔离、通信、预加载等</td></tr><tr><td><strong>Module Federation</strong></td><td>Webpack 5 原生能力</td><td>应用之间<strong>运行时共享模块</strong>，remote 暴露组件、host 通过 <code>import(&#39;remote/xxx&#39;)</code> 使用</td></tr><tr><td><strong>wujie</strong></td><td>iframe + WebComponent</td><td>用 iframe 提供天然 JS/CSS 隔离，用 WebComponent 挂载 UI</td></tr><tr><td><strong>micro-app</strong></td><td>京东方案，WebComponent 封装</td><td>类 iframe 语义但用自定义元素，隔离靠 sandbox 实现</td></tr></tbody></table><p><strong>qiankun / single-spa 的工作流</strong></p><ol><li><strong>注册子应用</strong>：告诉主应用每个子应用的名字、入口 URL、激活规则（路由前缀）、容器 DOM。</li><li><strong>路由变化</strong>：single-spa 监听 <code>popstate</code> / <code>hashchange</code>，匹配激活规则。</li><li><strong>加载子应用</strong>：fetch 入口 HTML，解析出 <code>&lt;script&gt;</code> / <code>&lt;link&gt;</code>，把 JS 拿下来通过 <code>new Function</code> 或 <code>eval</code> 执行。</li><li><strong>生命周期</strong>：调用子应用暴露的 <code>bootstrap</code> → <code>mount(props)</code> → <code>unmount()</code>，把 DOM 挂到指定容器。</li><li><strong>JS 沙箱 / 样式隔离</strong>：qiankun 在 mount 时替换 <code>window</code> 代理（Proxy 沙箱），unmount 时还原。</li></ol><p><strong>Module Federation 的工作流</strong></p><ul><li>Host 应用（消费者）声明 <code>remotes: { app1: &#39;app1@http://cdn/app1/remoteEntry.js&#39; }</code>。</li><li>Remote 应用（提供者）声明 <code>exposes: { &#39;./Button&#39;: &#39;./src/Button&#39; }</code> 生成 <code>remoteEntry.js</code>。</li><li>运行时 Host 动态 import 时，Webpack runtime 先加载 remoteEntry，从中拿到 <code>get()</code> 方法，再 get 到具体模块。</li><li>依赖共享：<code>shared: { react: { singleton: true } }</code>，双方共用同一份 React 实例，避免多副本。</li></ul><p><strong>JS 沙箱的常见实现</strong></p><ul><li><strong>快照沙箱</strong>（qiankun 老版本）：mount 时记录 window 快照，unmount 时恢复。缺点是所有子应用共享同一个 window，<strong>只能单例</strong>。</li><li><strong>Proxy 沙箱</strong>（qiankun 主流）：给每个子应用一个 Proxy 对象作为 fakeWindow，读写属性都在自己的 fakeWindow 上；子应用代码通过 <code>new Function(&#39;window&#39;, code)(fakeWindow)</code> 执行。缺点：性能开销，某些依赖真实 window 全局的第三方库仍会污染（例如手动 <code>document.body.__setup__</code> 之类）。</li><li><strong>iframe 沙箱</strong>（wujie）：直接放子应用在隐藏 iframe 里跑 JS，DOM 用 shadow / WebComponent 桥接。<strong>最彻底</strong>，但 iframe 首次开销大、跨域限制多。</li></ul><p><strong>样式隔离</strong></p><ul><li><strong>BEM / CSS Modules / CSS-in-JS</strong>：从源码层面约束类名唯一，最彻底也最轻量。</li><li><strong>动态 scoping</strong>（qiankun <code>experimentalStyleIsolation: true</code>）：mount 时给子应用容器加唯一属性，重写 CSS 规则加前缀选择器。有性能成本，兼容性一般。</li><li><strong>Shadow DOM</strong>（<code>strictStyleIsolation: true</code> 或 wujie / micro-app）：把子应用挂到 Shadow root 里，样式天然不外泄。缺点：全局样式、字体、CSS 变量传入需要额外处理，某些 UI 库（Ant Design 老版本）依赖 body 挂 modal，会跳出 shadow root。</li></ul><h2 id="追问-1-module-federation-和-qiankun-该怎么选" tabindex="-1">追问 1：Module Federation 和 qiankun 该怎么选？ <a class="header-anchor" href="#追问-1-module-federation-和-qiankun-该怎么选" aria-label="Permalink to &quot;追问 1：Module Federation 和 qiankun 该怎么选？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>qiankun</strong>： <ul><li>优点：应用<strong>自治</strong>（每个子应用独立部署、独立技术栈），主应用几乎零改造。</li><li>缺点：加载入口是完整应用（HTML + 全部 assets），资源体积大；沙箱有边界情况；技术栈之间共享依赖靠约定，不天然。</li></ul></li><li><strong>Module Federation</strong>： <ul><li>优点：<strong>模块级共享</strong>（一个组件、一个函数就能暴露），依赖共享由 Webpack 处理；类型友好；构建期知道 remote 存在，type-check 更好。</li><li>缺点：<strong>强耦合</strong>于 Webpack（或 Vite 的 <code>@originjs/vite-plugin-federation</code>）；需要各团队协商 remoteEntry 契约；不适合完全独立技术栈的场景。</li></ul></li><li>经验：<strong>同技术栈 + 组件级共享</strong>用 Module Federation；<strong>多技术栈 + 应用级拼装</strong>用 qiankun / wujie。也可以混用：主应用是 qiankun 壳，几个共享组件用 MF。</li></ul><h2 id="追问-2-微前端的-js-沙箱能真正做到-完全隔离-吗-边界在哪" tabindex="-1">追问 2：微前端的 JS 沙箱能真正做到&quot;完全隔离&quot;吗？边界在哪？ <a class="header-anchor" href="#追问-2-微前端的-js-沙箱能真正做到-完全隔离-吗-边界在哪" aria-label="Permalink to &quot;追问 2：微前端的 JS 沙箱能真正做到&quot;完全隔离&quot;吗？边界在哪？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>无法完全隔离</strong>，只能做到&quot;大多数场景够用&quot;： <ul><li>Proxy 沙箱能隔离 <code>window.xxx = &#39;a&#39;</code> 这种赋值，但 DOM 是共享的：一个子应用往 <code>document.body</code> 加节点，另一个能看到。</li><li>事件监听器：<code>window.addEventListener(&#39;resize&#39;)</code> 的 listener 保存在真实 window 上，unmount 时如果忘 remove 会泄漏。qiankun 会拦截 addEventListener 帮忙记录、卸载。</li><li>全局副作用：修改 <code>Array.prototype</code>、<code>Object.prototype</code> 无法沙箱化（沙箱不管原型链）。</li><li>定时器 / RAF / MutationObserver：需要 patch 拿到句柄，unmount 时统一清理。</li></ul></li><li>想要真正隔离，得用 <strong>iframe</strong>（内含独立 window/document/globalThis）。代价是通信复杂、首屏慢、跨域 cookie 麻烦。</li><li>结论：沙箱是<strong>工程妥协</strong>，选方案时明确&quot;我到底要隔离到什么程度&quot;，业务能约束就靠约束，实在不行才 iframe。</li></ul><h2 id="追问-3-微前端里的公共依赖-react、组件库-怎么共享-重复打包如何避免" tabindex="-1">追问 3：微前端里的公共依赖（React、组件库）怎么共享？重复打包如何避免？ <a class="header-anchor" href="#追问-3-微前端里的公共依赖-react、组件库-怎么共享-重复打包如何避免" aria-label="Permalink to &quot;追问 3：微前端里的公共依赖（React、组件库）怎么共享？重复打包如何避免？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>externals + CDN</strong>：多个应用把 React 声明成 <code>externals: &#39;React&#39;</code>，页面里 <code>&lt;script src=&quot;https://cdn/react.production.min.js&quot;&gt;</code> 引入。所有应用共享一个 React 实例，同版本共用浏览器缓存。</li><li><strong>Module Federation <code>shared</code></strong>：<code>shared: { react: { singleton: true, requiredVersion: &#39;^18&#39; } }</code>，MF runtime 会协商选一个版本用，加载时只下载一次。</li><li><strong>主应用注入</strong>：qiankun 里主应用先加载 React 到全局，子应用通过 <code>window.React</code> 使用。</li><li>需要注意： <ul><li><strong>同一版本</strong>才能共享，跨大版本 React 强共享会崩（hooks 上下文不匹配）；</li><li><strong>同一实例</strong>才能保持 context：如果两个应用各自打了自己的 React，<code>useContext</code> 的 Provider/Consumer 拿不到同一份，跨应用状态失败；</li><li><strong>组件库、i18n、状态管理</strong>同理，能共享的都要共享，节省体积同时避免&quot;两个 antd context&quot;问题。</li></ul></li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/domains/arch/RESOURCES">工程架构 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://single-spa.js.org/docs/getting-started-overview" target="_blank" rel="noreferrer">single-spa Docs</a>：应用级微前端编排、生命周期与路由集成。</li><li><a href="https://module-federation.io/guide/start/index.html" target="_blank" rel="noreferrer">Module Federation Docs</a>：运行时模块共享、<code>shared</code> 依赖协商与 remote 暴露。</li><li><a href="https://qiankun.umijs.org/zh/guide" target="_blank" rel="noreferrer">qiankun</a>：基于 single-spa 的 JS 沙箱、样式隔离与国内生态实践。</li></ul>',28)])])}const h=o(i,[["render",a]]);export{p as __pageData,h as default};
